package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testTrim() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false);
        CSVFormat csvFormatSpy = mock(CSVFormat.class);
        CharSequence charSequence = "   test   ";

        // When
        Method trimMethod = CSVFormat.class.getDeclaredMethod("trim", CharSequence.class);
        trimMethod.setAccessible(true);
        when(csvFormatSpy.trim(charSequence)).thenReturn((CharSequence) trimMethod.invoke(csvFormat, charSequence));
        CharSequence result = (CharSequence) trimMethod.invoke(csvFormatSpy, charSequence);

        // Then
        assertEquals("test", result.toString());
    }
}
